// ======================================================================
// KVADRÁNS SZÉTVÁLASZTÓ – ROBUSZTUS VERZIÓ
// (kezeli az új és régi fejlécformákat is, pl. "3. KVADRÁNS (bal alsó)" vagy "KVADRÁNS (bal alsó)")
// + Megjegyzes_fo blokk kinyerése
// ======================================================================
// 1) Forrás szöveg
let fullReport = $input.item.json.output ?? "";
// 2) Normalizálás
fullReport = fullReport
  .replace(/\\n/g, "\n")   // literal "\n" -> newline
  .replace(/\r\n/g, "\n")  // CRLF -> LF
  .trim();
// 2/b) Megjegyzes_fo blokk kinyerése
// Handles **Megjegyzes_fo:** (bold markdown) and plain Megjegyzes_fo:
// Works whether the block appears before or after the quadrant sections
let megjegyzesFo = "";
const megjegyzesMatch = fullReport.match(
  /\*{0,2}Megjegyzes_fo:\*{0,2}\s*([\s\S]*?)(?=\n---\s*(?:END|$)|\n##\s*FOGAK|\nFOGAK:|\n###\s*\d+\.?\s*KVADRÁNS|\n\d+\.?\s*KVADRÁNS|$)/i
);
if (megjegyzesMatch) {
  megjegyzesFo = `Megjegyzes_fo:\n${megjegyzesMatch[1].trim()}`;
}
// 3) Rugalmas kvadráns-fejléc minták (### nélkül is működik)
const headingPatterns = {
  q1: /(?:###\s*)?(?:JOBB\s+FELSŐ\s+KVADRÁNS|1\.?\s*KVADRÁNS\s*\([^)]*\)|KVADRÁNS\s*\(jobb felső\))/i,
  q2: /(?:###\s*)?(?:BAL\s+FELSŐ\s+KVADRÁNS|2\.?\s*KVADRÁNS\s*\([^)]*\)|KVADRÁNS\s*\(bal felső\))/i,
  q3: /(?:###\s*)?(?:BAL\s+ALSÓ\s+KVADRÁNS|3\.?\s*KVADRÁNS\s*\([^)]*\)|KVADRÁNS\s*\(bal alsó\))/i,
  q4: /(?:###\s*)?(?:JOBB\s+ALSÓ\s+KVADRÁNS|4\.?\s*KVADRÁNS\s*\([^)]*\)|KVADRÁNS\s*\(jobb alsó\))/i,
};
// 4) Fejlécpozíciók keresése
function findIndex(re) {
  const m = fullReport.match(re);
  if (!m) return -1;
  return fullReport.indexOf(m[0]);
}
const starts = [
  { key: "TEETHLQ1", title: "### 1. KVADRÁNS (jobb felső)", idx: findIndex(headingPatterns.q1) },
  { key: "TEETHLQ2", title: "### 2. KVADRÁNS (bal felső)",  idx: findIndex(headingPatterns.q2) },
  { key: "TEETHLQ3", title: "### 3. KVADRÁNS (bal alsó)",   idx: findIndex(headingPatterns.q3) },
  { key: "TEETHLQ4", title: "### 4. KVADRÁNS (jobb alsó)",  idx: findIndex(headingPatterns.q4) },
];
// 5) Létező kvadránsok kiválogatása és sorrendezése
const existing = starts
  .filter(s => s.idx >= 0)
  .sort((a, b) => a.idx - b.idx);
console.log("Felismerve:", existing.map(e => e.title));
// Ha nincs egy sem, visszaadunk 4 üres ágat + Megjegyzes_fo-t
if (existing.length === 0) {
  return [
    { json: { section: "MEGJEGYZES_FO", content: megjegyzesFo, length: megjegyzesFo.length } },
    { json: { section: "TEETHLQ1", content: "", length: 0 } },
    { json: { section: "TEETHLQ2", content: "", length: 0 } },
    { json: { section: "TEETHLQ3", content: "", length: 0 } },
    { json: { section: "TEETHLQ4", content: "", length: 0 } },
  ];
}
// 6) Kivágás: kvadráns tartalom a saját címsorától a következőig
function sliceSection(startIdx, nextStartIdxExclusive) {
  const end = (nextStartIdxExclusive >= 0 ? nextStartIdxExclusive : fullReport.length);
  return fullReport.slice(startIdx, end).trim();
}
const resultsMap = {
  TEETHLQ1: "",
  TEETHLQ2: "",
  TEETHLQ3: "",
  TEETHLQ4: "",
};
for (let i = 0; i < existing.length; i++) {
  const cur = existing[i];
  const next = existing[i + 1];
  const raw = sliceSection(cur.idx, next ? next.idx : -1);
  // Eltávolítjuk a saját fejlécet, majd egységes címet teszünk elé
  const nl = raw.indexOf("\n");
  const body = nl >= 0 ? raw.slice(nl + 1).trim() : "";
  const finalText = `${cur.title}\n\n${body}`.trim();
  resultsMap[cur.key] = finalText;
}
// 6b) Clean trailing Megjegyzes_fo / --- END --- from the last quadrant
for (const key of ["TEETHLQ4", "TEETHLQ3", "TEETHLQ2", "TEETHLQ1"]) {
  if (resultsMap[key]) {
    resultsMap[key] = resultsMap[key]
      .replace(/\n+---\s*\n+\*{0,2}Megjegyzes_fo:\*{0,2}[\s\S]*$/, "")
      .replace(/\n+---\s*END\s*---\s*$/, "")
      .trim();
  }
}
// 7) Kimenet – Megjegyzes_fo + 4 kvadráns ág, még ha üres is
const out = [
  { json: { section: "MEGJEGYZES_FO", content: megjegyzesFo, length: megjegyzesFo.length } },
  { json: { section: "TEETHLQ1", content: resultsMap.TEETHLQ1, length: resultsMap.TEETHLQ1.length } },
  { json: { section: "TEETHLQ2", content: resultsMap.TEETHLQ2, length: resultsMap.TEETHLQ2.length } },
  { json: { section: "TEETHLQ3", content: resultsMap.TEETHLQ3, length: resultsMap.TEETHLQ3.length } },
  { json: { section: "TEETHLQ4", content: resultsMap.TEETHLQ4, length: resultsMap.TEETHLQ4.length } },
];
return out;

// MERGE NODE (kód2) - Explicit Content Recovery v4.2
// This version is "stubborn" about finding the MEGJEGYZES_FO content.

const inputs = $input.all();
const comprehensiveData = {};
let globalComment = "";

console.log(`Merge Node: Analyzing ${inputs.length} inputs...`);

inputs.forEach((input, index) => {
    const data = input.json || {};

    // 1. MANDATORY CHECK: Look for the specific 'section': 'MEGJEGYZES_FO' pattern
    if (data.section === "MEGJEGYZES_FO" && data.content) {
        console.log(`Input ${index}: Matched MEGJEGYZES_FO section!`);
        let text = data.content.trim();
        // Strip the "Megjegyzes_fo:\n" label and trailing "---" the AI adds
        text = text.replace(/^Megjegyzes_fo:\s*/i, "").replace(/\s*---\s*$/, "").trim();
        globalComment = globalComment ? `${globalComment}\n${text}` : text;
    }

    // 2. BACKUP CHECK: Search for 'content' or 'megjegyzes_fo' in raw data
    const searchIn = (obj) => {
        if (!obj || typeof obj !== 'object') return;

        for (const [key, value] of Object.entries(obj)) {
            const lowKey = key.toLowerCase();

            // If we find clinical megjegyzes keys
            if (['megjegyzes_fo', 'megjegyzés_fo', 'megjegyzes_fo_'].includes(lowKey)) {
                if (value && typeof value === 'string' && value.trim()) {
                    globalComment = globalComment ? `${globalComment}\n${value.trim()}` : value.trim();
                }
            }

            // Tooth Data (2-digits)
            if (/^\d{2}$/.test(key) && value && typeof value === 'object') {
                const hasRealData = Object.keys(value).some(k => k !== "Megjegyzes" && value[k] !== "" && value[k] !== false);
                if (!comprehensiveData[key]) {
                    comprehensiveData[key] = value;
                } else if (hasRealData) {
                    comprehensiveData[key] = { ...comprehensiveData[key], ...value };
                }
            }
        }
    };

    searchIn(data);
    if (data.body) searchIn(data.body);
});

// Final Check: Reach out to "AI Agent 2" if still empty
if (!globalComment) {
    try {
        const agent = $items("AI Agent 2")[0].json;
        const text = agent.output || agent.content || "";
        const match = text.match(/## Megjegyzes_fo:\s*([\s\S]*?)(?:\s*--- END ---|$)/i);
        globalComment = match ? match[1].trim() : (text.includes("---") ? text.trim() : "");
    } catch (e) { }
}

// Ensure the key exists in the final object
comprehensiveData.MEGJEGYZES_FO = globalComment || "";

// Add Metadata from Webhook
try {
    const web = $items("Webhook")[0].json;
    const b = web.body || web;
    comprehensiveData.metadata = {
        domain: b.flexi_domain || b.domain,
        paciensId: b.PaciensID,
        email: b.flexi_username || b.flexi_email,
        password: b.flexi_pw || b.flexi_password
    };
} catch (e) { }

return [{ json: comprehensiveData }];

// Sparse → Full JSON konverter (Smart Split + Megjegyzes + '..' fix)
const TOOTH_NUMBERS = ["11","12","13","14","15","16","17","18"];

// --- MAIN ---
const root = $input.first().json;
const sparseData = Array.isArray(root) ? root[0]?.parsed : root?.parsed;

if (!sparseData || typeof sparseData !== 'object') {
  console.warn('Nincs érvényes parsed objektum a bemenetben.');
  return [{ json: {} }];
}

const result = {};
// 1) Inicializálás: minden fog kap üres objektumot és üres Megjegyzes-t
for (const n of TOOTH_NUMBERS) result[n] = { Megjegyzes: "" };

// 2) Aktiv path-ok + Megjegyzes átvétele
for (const [toothNum, toothData] of Object.entries(sparseData)) {
  if (!result[toothNum]) {
    console.warn(`Ismeretlen fog szám: ${toothNum}`);
    continue;
  }

  const activePaths = Array.isArray(toothData?.active_properties) ? toothData.active_properties : [];
  for (const path of activePaths) {
    try { setNestedProperty(result[toothNum], path, true); }
    catch (err) { console.error(`Hiba a path beállításában: ${path} (fog: ${toothNum})`, err); }
  }

  const note = typeof toothData?.Megjegyzes === 'string' ? toothData.Megjegyzes.trim() : "";
  result[toothNum].Megjegyzes = note;
}

return [{ json: result }];

// --- HELPERS ---
// Speciális split: kezeli a '..' mint elválasztót (top kulcs ponttal a végén),
// és a 3. szintetől a pontok megmaradnak a végső kulcsban.
function smartSplit(path) {
  if (path.includes('..')) {
    // Pl: "Peripacialis_elv..Altalanos.Cysta_-_Periapicalis_elv."
    const idx = path.indexOf('..');
    const top = path.slice(0, idx) + '.';      // "Peripacialis_elv."
    const rest = path.slice(idx + 2);          // "Altalanos.Cysta_-_Periapicalis_elv."
    const dot = rest.indexOf('.');
    if (dot === -1) return [top, rest];        // ritka eset, de kezeljük
    const second = rest.slice(0, dot);         // "Altalanos"
    const tail = rest.slice(dot + 1);          // "Cysta_-_Periapicalis_elv."
    return [top, second, tail];
  }

  // Normál eset: első két rész külön, maradék egyben
  const parts = path.split('.');
  if (parts.length <= 2) return parts;
  return [parts[0], parts[1], parts.slice(2).join('.')];
}

function setNestedProperty(obj, path, value) {
  const keys = smartSplit(path);
  let cur = obj;
  for (let i = 0; i < keys.length - 1; i++) {
    const k = keys[i];
    if (!cur[k] || typeof cur[k] !== 'object') cur[k] = {};
    cur = cur[k];
  }
  cur[keys[keys.length - 1]] = value;
}

